import numpy as np

def compute_JK_contributions(C, eri, n_occ):
    """Compute Coulomb and Exchange energy contributions."""
    n_ao = C.shape[0]

    # Build density matrix
    C_occ = C[:, :n_occ]
    P = 2.0 * C_occ @ C_occ.T

    # Coulomb energy: ½ Σ Pμν Pλσ (μν|λσ)
    J_energy = 0.0
    for mu in range(n_ao):
        for nu in range(n_ao):
            for lam in range(n_ao):
                for sig in range(n_ao):
                    J_energy += 0.5 * P[mu, nu] * P[lam, sig] * eri[mu, nu, lam, sig]

    # Exchange energy: -¼ Σ Pμν Pλσ (μσ|λν)
    K_energy = 0.0
    for mu in range(n_ao):
        for nu in range(n_ao):
            for lam in range(n_ao):
                for sig in range(n_ao):
                    K_energy += 0.25 * P[mu, nu] * P[lam, sig] * eri[mu, sig, lam, nu]

    return J_energy, K_energy

# Test
C = np.array([[1.0], [0.0]])
eri = np.zeros((2, 2, 2, 2))
eri[0, 0, 0, 0] = 0.6

J, K = compute_JK_contributions(C, eri, 1)
print(f"Coulomb: {J:.4f}, Exchange: {K:.4f}")
